#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=50005;
ll n,l,c[N],s[N],dp[N][3];
ll dq[N],L,R;
double fun(ll j1,ll j2)
{
	return (double)(dp[j2][2]+dp[j2][1]-dp[j1][2]-dp[j1][1])/(dp[j2][0]-dp[j1][0]);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>l;
	for(int i=1;i<=n;i++) 
	{
		cin>>c[i];
		s[i]=s[i-1]+c[i];
		dp[i][0]=s[i]+i;
		dp[i][1]=(dp[i][0]+1+l)*(dp[i][0]+1+l);
	}
	dp[0][1]=(l+1)*(l+1);
	for(int i=1;i<=n;i++)
	{
		while(L<R&&fun(dq[L],dq[L+1])<2*dp[i][0]) L++;
		int j=dq[L];
		dp[i][2]=dp[j][2]+(dp[i][0]-dp[j][0]-1-l)*(dp[i][0]-dp[j][0]-1-l);
		while(L<R&fun(dq[R-1],dq[R])>fun(dq[R],i)) R--;
		dq[++R]=i;
	}
	cout<<dp[n][2];
	return 0;
}
